def parse_duration(s: str) -> int:
    """Convert a duration string like '2h30m', '45m', '1h', '90s' to total seconds."""
    import re
    pattern = r'^((\d+)h)?((\d+)m)?((\d+)s)?$'
    match = re.fullmatch(pattern, s)
    if not match:
        raise ValueError("Invalid duration format")
    h, m, sec = match.group(2), match.group(4), match.group(6)
    total = 0
    if h:
        total += int(h) * 3600
    if m:
        total += int(m) * 60
    if sec:
        total += int(sec)
    if total == 0:
        raise ValueError("Empty duration")
    return total
